mapper.select:
select cost.match_user_name, cost.match_user_id, c from t_rpt_base_cost cost left join t_ctr_contract contract on cost.match_user_id = contract.match_user_id
date_format(contract_time, '%Y-%m') = #{baseDate}
and cost.branch_cd = #{branchCd}
and cost.match_user_name like concat('%', #{matchUserName}, '%')
group by
